module nand4 (
    input a,
    input b,
    input c,
    input d,
    output y
);

    wire temp;

    assign temp = a & b & c & d;
    assign y = ~temp;

  always @(*) begin
    if (1'b0) begin
      if (c & d) begin
        y <= 1'b1;
      end else begin
        y <= 1'b0;
      end;
    end
  end

endmodule

